CREATE TABLE TB_AMANAJE_CLIENTE (
    ID_CLIENTE NUMBER GENERATED BY DEFAULT AS IDENTITY,
    NM_CLIENTE VARCHAR2(150) NOT NULL,
    TP_CLIENTE VARCHAR2(30) NOT NULL,
    NR_DOCUMENTO VARCHAR2(30),
    DS_EMAIL_CONTATO VARCHAR2(200),
    NR_TELEFONE VARCHAR2(30),
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DELETADO_EM TIMESTAMP,
    ID_DELETADO_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_CLIENTE PRIMARY KEY (ID_CLIENTE),
    CONSTRAINT UQ_AMANAJE_CLIENTE_DOC UNIQUE (NR_DOCUMENTO),
    CONSTRAINT CK_AMANAJE_CLIENTE_TIPO CHECK (TP_CLIENTE IN ('GOVERNO_DEFESA_CIVIL', 'ONG', 'FAZENDA_PRIVADO', 'COOPERATIVA', 'PESQUISA_UNIVERSIDADE')),
    CONSTRAINT CK_AMANAJE_CLIENTE_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_CLIENTE_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DELETADO_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    )
);

COMMENT ON TABLE TB_AMANAJE_CLIENTE IS 'Organizações que contratam, operam ou utilizam o serviço de monitoramento climático e ambiental.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.ID_CLIENTE IS 'Identificador único do cliente.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.NM_CLIENTE IS 'Nome da instituição, organização, fazenda, cooperativa ou entidade de pesquisa.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.TP_CLIENTE IS 'Tipo do cliente: GOVERNO_DEFESA_CIVIL, ONG, FAZENDA_PRIVADO, COOPERATIVA ou PESQUISA_UNIVERSIDADE.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.NR_DOCUMENTO IS 'Documento institucional do cliente, como CNPJ ou identificador equivalente.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.DS_EMAIL_CONTATO IS 'E-mail principal de contato do cliente.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.NR_TELEFONE IS 'Telefone principal de contato do cliente.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.ST_ATIVO IS 'Indica exclusão lógica do cliente: S = ativo, N = inativo.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.DT_CRIADO_EM IS 'Data e hora de criação do registro.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.DT_ATUALIZADO_EM IS 'Data e hora da última atualização do registro.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.DT_DELETADO_EM IS 'Data e hora da exclusão lógica.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.ID_DELETADO_POR IS 'Identificador do usuário que realizou a exclusão lógica, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_CLIENTE.DS_MOTIVO_EXCLUSAO IS 'Justificativa opcional para auditoria da exclusão lógica.';

CREATE TABLE TB_AMANAJE_USUARIO (
