    CONSTRAINT CK_AMANAJE_USUARIO_STATUS CHECK (ST_USUARIO IN ('ATIVO', 'BLOQUEADO', 'PENDENTE', 'INATIVO')),
    CONSTRAINT CK_AMANAJE_USUARIO_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_USUARIO_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DELETADO_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_USUARIO_CLIENTE FOREIGN KEY (ID_CLIENTE)
        REFERENCES TB_AMANAJE_CLIENTE (ID_CLIENTE),
    CONSTRAINT FK_USUARIO_DELETADO_POR FOREIGN KEY (ID_DELETADO_POR)
        REFERENCES TB_AMANAJE_USUARIO (ID_USUARIO)
);

