CREATE TABLE TB_AMANAJE_ESTACAO_IOT (
    ID_ESTACAO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER NOT NULL,
    CD_ESTACAO VARCHAR2(40) NOT NULL,
    NM_ESTACAO VARCHAR2(120) NOT NULL,
    TP_ESTACAO VARCHAR2(20) NOT NULL,
    ST_ESTACAO VARCHAR2(20) DEFAULT 'ATIVA' NOT NULL,
    NR_LATITUDE NUMBER(9,6),
    NR_LONGITUDE NUMBER(9,6),
    DT_ULTIMA_COMUNICACAO TIMESTAMP,
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DELETADO_EM TIMESTAMP,
    ID_DELETADO_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_ESTACAO PRIMARY KEY (ID_ESTACAO),
    CONSTRAINT UQ_AMANAJE_ESTACAO_CODIGO UNIQUE (CD_ESTACAO),
    CONSTRAINT UQ_AMANAJE_ESTACAO_ID_REGIAO UNIQUE (ID_ESTACAO, ID_REGIAO),
    CONSTRAINT CK_AMANAJE_ESTACAO_TIPO CHECK (TP_ESTACAO IN ('REAL', 'SIMULADA', 'REFERENCIA')),
    CONSTRAINT CK_AMANAJE_ESTACAO_STATUS CHECK (ST_ESTACAO IN ('ATIVA', 'INATIVA', 'MANUTENCAO', 'FALHA', 'SEM_COMUNICACAO')),
    CONSTRAINT CK_AMANAJE_ESTACAO_LAT CHECK (NR_LATITUDE IS NULL OR NR_LATITUDE BETWEEN -90 AND 90),
    CONSTRAINT CK_AMANAJE_ESTACAO_LONG CHECK (NR_LONGITUDE IS NULL OR NR_LONGITUDE BETWEEN -180 AND 180),
    CONSTRAINT CK_AMANAJE_ESTACAO_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_ESTACAO_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DELETADO_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_ESTACAO_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONITORADA (ID_REGIAO),
    CONSTRAINT FK_ESTACAO_DELETADO_POR FOREIGN KEY (ID_DELETADO_POR)
        REFERENCES TB_AMANAJE_USUARIO (ID_USUARIO)
);

