CREATE TABLE TB_AMANAJE_LEITURA_IOT (
    ID_LEITURA NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_ESTACAO NUMBER NOT NULL,
    ID_REGIAO NUMBER NOT NULL,
    NR_DISTANCIA_AGUA_CM NUMBER(8,2),
    NR_NIVEL_AGUA_PCT NUMBER(5,2),
    NR_INCLINACAO_GRAUS NUMBER(6,2),
    NR_VIBRACAO NUMBER(8,4),
    NR_PRESSAO_HPA NUMBER(8,2),
    NR_PM25 NUMBER(8,2),
    NR_PM10 NUMBER(8,2),
    DT_LEITURA TIMESTAMP NOT NULL,
    DT_RECEBIDO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    ST_VALIDA CHAR(1) DEFAULT 'S' NOT NULL,
    DS_MOTIVO_INVALIDACAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_LEITURA PRIMARY KEY (ID_LEITURA),
    CONSTRAINT UQ_AMANAJE_LEITURA_ID_REGIAO UNIQUE (ID_LEITURA, ID_REGIAO),
    CONSTRAINT CK_AMANAJE_LEITURA_AGUA CHECK (NR_NIVEL_AGUA_PCT IS NULL OR NR_NIVEL_AGUA_PCT BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_LEITURA_PRESSAO CHECK (NR_PRESSAO_HPA IS NULL OR NR_PRESSAO_HPA BETWEEN 800 AND 1200),
    CONSTRAINT CK_AMANAJE_LEITURA_PM25 CHECK (NR_PM25 IS NULL OR NR_PM25 >= 0),
    CONSTRAINT CK_AMANAJE_LEITURA_PM10 CHECK (NR_PM10 IS NULL OR NR_PM10 >= 0),
    CONSTRAINT CK_AMANAJE_LEITURA_VALIDA CHECK (ST_VALIDA IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_LEITURA_INV CHECK (
        (ST_VALIDA = 'S' AND DS_MOTIVO_INVALIDACAO IS NULL)
        OR
        (ST_VALIDA = 'N')
    ),
    CONSTRAINT FK_LEITURA_ESTACAO_REGIAO FOREIGN KEY (ID_ESTACAO, ID_REGIAO)
        REFERENCES TB_AMANAJE_ESTACAO_IOT (ID_ESTACAO, ID_REGIAO)
);

