    CONSTRAINT PK_AMANAJE_OBSERVACAO PRIMARY KEY (ID_OBSERVACAO),
    CONSTRAINT UQ_AMANAJE_OBSERVACAO_ID_REGIAO UNIQUE (ID_OBSERVACAO, ID_REGIAO),
    CONSTRAINT CK_AMANAJE_OBS_UMIDADE CHECK (NR_UMIDADE_PCT IS NULL OR NR_UMIDADE_PCT BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_OBS_PREC CHECK (NR_PRECIPITACAO_MM IS NULL OR NR_PRECIPITACAO_MM >= 0),
    CONSTRAINT CK_AMANAJE_OBS_VENTO CHECK (NR_VENTO_KMH IS NULL OR NR_VENTO_KMH >= 0),
    CONSTRAINT CK_AMANAJE_OBS_PRESSAO CHECK (NR_PRESSAO_HPA IS NULL OR NR_PRESSAO_HPA BETWEEN 800 AND 1200),
    CONSTRAINT CK_AMANAJE_OBS_UV CHECK (NR_INDICE_UV IS NULL OR NR_INDICE_UV BETWEEN 0 AND 20),
    CONSTRAINT FK_OBSERVACAO_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONITORADA (ID_REGIAO)
);

COMMENT ON TABLE TB_AMANAJE_OBSERVACAO_CLIMATICA IS 'Dados climáticos públicos normalizados por integração externa e associados a uma região monitorada.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.ID_OBSERVACAO IS 'Identificador único da observação climática externa.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.ID_REGIAO IS 'Região monitorada relacionada à observação climática.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NM_FONTE IS 'Fonte pública ou serviço usado para obter os dados climáticos.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_TEMPERATURA_C IS 'Temperatura em graus Celsius.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_UMIDADE_PCT IS 'Umidade relativa do ar em percentual.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_PRECIPITACAO_MM IS 'Precipitação em milímetros.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_VENTO_KMH IS 'Velocidade do vento em km/h.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_PRESSAO_HPA IS 'Pressão atmosférica externa em hPa.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_RADIACAO_SOLAR IS 'Radiação solar informada pela fonte externa.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.NR_INDICE_UV IS 'Índice ultravioleta informado pela fonte externa.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.DT_OBSERVACAO IS 'Data e hora da observação climática externa.';
COMMENT ON COLUMN TB_AMANAJE_OBSERVACAO_CLIMATICA.DT_CRIADO_EM IS 'Data e hora de criação do registro no banco.';

CREATE TABLE TB_AMANAJE_AVALIACAO_RISCO (
    ID_AVALIACAO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER NOT NULL,
    ID_LEITURA NUMBER,
    ID_OBSERVACAO NUMBER,
    TP_RISCO VARCHAR2(30) NOT NULL,
    NR_SCORE_RISCO NUMBER(5,2) NOT NULL,
    TP_NIVEL_RISCO VARCHAR2(20) NOT NULL,
    DS_MOTIVO VARCHAR2(500) NOT NULL,
    DT_AVALIACAO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_AVALIACAO PRIMARY KEY (ID_AVALIACAO),
    CONSTRAINT UQ_AMANAJE_AVALIACAO_ID_REGIAO UNIQUE (ID_AVALIACAO, ID_REGIAO),
    CONSTRAINT CK_AMANAJE_AVALIACAO_TIPO CHECK (TP_RISCO IN ('ENCHENTE', 'DESLIZAMENTO', 'TEMPESTADE', 'QUALIDADE_AR')),
    CONSTRAINT CK_AMANAJE_AVALIACAO_SCORE CHECK (NR_SCORE_RISCO BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_AVALIACAO_NIVEL CHECK (TP_NIVEL_RISCO IN ('BAIXO', 'MODERADO', 'ALTO', 'CRITICO')),
    CONSTRAINT CK_AMANAJE_AVALIACAO_ORIGEM CHECK (ID_LEITURA IS NOT NULL OR ID_OBSERVACAO IS NOT NULL),
    CONSTRAINT CK_AMANAJE_AVALIACAO_SCORE_NIVEL CHECK (
        (TP_NIVEL_RISCO = 'BAIXO' AND NR_SCORE_RISCO >= 0 AND NR_SCORE_RISCO < 25)
        OR
        (TP_NIVEL_RISCO = 'MODERADO' AND NR_SCORE_RISCO >= 25 AND NR_SCORE_RISCO < 50)
        OR
        (TP_NIVEL_RISCO = 'ALTO' AND NR_SCORE_RISCO >= 50 AND NR_SCORE_RISCO < 75)
        OR
        (TP_NIVEL_RISCO = 'CRITICO' AND NR_SCORE_RISCO >= 75 AND NR_SCORE_RISCO <= 100)
    ),
    CONSTRAINT FK_AVALIACAO_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONITORADA (ID_REGIAO),
    CONSTRAINT FK_AVALIACAO_LEITURA_REGIAO FOREIGN KEY (ID_LEITURA, ID_REGIAO)
        REFERENCES TB_AMANAJE_LEITURA_IOT (ID_LEITURA, ID_REGIAO),
    CONSTRAINT FK_AVALIACAO_OBSERVACAO_REGIAO FOREIGN KEY (ID_OBSERVACAO, ID_REGIAO)
        REFERENCES TB_AMANAJE_OBSERVACAO_CLIMATICA (ID_OBSERVACAO, ID_REGIAO)
);

COMMENT ON TABLE TB_AMANAJE_AVALIACAO_RISCO IS 'Resultados calculados pela API para risco ambiental por região e categoria.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.ID_AVALIACAO IS 'Identificador único da avaliação de risco.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.ID_REGIAO IS 'Região monitorada avaliada.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.ID_LEITURA IS 'Leitura IoT usada na avaliação, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.ID_OBSERVACAO IS 'Observação climática externa usada na avaliação, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.TP_RISCO IS 'Categoria do risco ambiental avaliado.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.NR_SCORE_RISCO IS 'Score de risco calculado entre 0 e 100.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.TP_NIVEL_RISCO IS 'Nível do risco: BAIXO, MODERADO, ALTO ou CRITICO.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.DS_MOTIVO IS 'Justificativa resumida para o score e nível de risco.';
COMMENT ON COLUMN TB_AMANAJE_AVALIACAO_RISCO.DT_AVALIACAO IS 'Data e hora da avaliação de risco.';

CREATE TABLE TB_AMANAJE_ALERTA (
    ID_ALERTA NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER NOT NULL,
    ID_AVALIACAO NUMBER NOT NULL,
    TP_ALERTA VARCHAR2(30) NOT NULL,
    TP_NIVEL VARCHAR2(20) NOT NULL,
    DS_TITULO VARCHAR2(150) NOT NULL,
    DS_ALERTA VARCHAR2(1000) NOT NULL,
    DS_RECOMENDACAO VARCHAR2(1000) NOT NULL,
    ST_ALERTA VARCHAR2(20) DEFAULT 'ABERTO' NOT NULL,
    DT_ALERTA TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_RESOLVIDO_EM TIMESTAMP,
    ST_ATIVO CHAR(1) DEFAULT 'S' NOT NULL,
    DT_CRIADO_EM TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_ATUALIZADO_EM TIMESTAMP,
    DT_DELETADO_EM TIMESTAMP,
    ID_DELETADO_POR NUMBER,
    DS_MOTIVO_EXCLUSAO VARCHAR2(255),

    CONSTRAINT PK_AMANAJE_ALERTA PRIMARY KEY (ID_ALERTA),
    CONSTRAINT CK_AMANAJE_ALERTA_TIPO CHECK (TP_ALERTA IN ('ENCHENTE', 'DESLIZAMENTO', 'TEMPESTADE', 'QUALIDADE_AR', 'OPERACIONAL')),
    CONSTRAINT CK_AMANAJE_ALERTA_NIVEL CHECK (TP_NIVEL IN ('BAIXO', 'MODERADO', 'ALTO', 'CRITICO')),
    CONSTRAINT CK_AMANAJE_ALERTA_STATUS CHECK (ST_ALERTA IN ('ABERTO', 'EM_ANALISE', 'RESOLVIDO', 'CANCELADO')),
    CONSTRAINT CK_AMANAJE_ALERTA_ATIVO CHECK (ST_ATIVO IN ('S', 'N')),
    CONSTRAINT CK_AMANAJE_ALERTA_RES CHECK (
        (ST_ALERTA = 'RESOLVIDO' AND DT_RESOLVIDO_EM IS NOT NULL)
        OR
        (ST_ALERTA <> 'RESOLVIDO')
    ),
    CONSTRAINT CK_AMANAJE_ALERTA_DEL CHECK (
        (ST_ATIVO = 'S' AND DT_DELETADO_EM IS NULL)
        OR
        (ST_ATIVO = 'N')
    ),
    CONSTRAINT FK_ALERTA_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONITORADA (ID_REGIAO),
    CONSTRAINT FK_ALERTA_AVALIACAO_REGIAO FOREIGN KEY (ID_AVALIACAO, ID_REGIAO)
        REFERENCES TB_AMANAJE_AVALIACAO_RISCO (ID_AVALIACAO, ID_REGIAO),
    CONSTRAINT FK_ALERTA_DELETADO_POR FOREIGN KEY (ID_DELETADO_POR)
        REFERENCES TB_AMANAJE_USUARIO (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_ALERTA IS 'Alertas gerados a partir de avaliações de risco para apoio à decisão institucional.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_ALERTA IS 'Identificador único do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_REGIAO IS 'Região monitorada relacionada ao alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_AVALIACAO IS 'Avaliação de risco que originou o alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.TP_ALERTA IS 'Tipo do alerta ambiental ou operacional.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.TP_NIVEL IS 'Nível do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_TITULO IS 'Título curto exibido em dashboard.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_ALERTA IS 'Descrição detalhada do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_RECOMENDACAO IS 'Recomendação operacional associada ao alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ST_ALERTA IS 'Status do ciclo de vida do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_ALERTA IS 'Data e hora de criação do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_RESOLVIDO_EM IS 'Data e hora de resolução do alerta.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ST_ATIVO IS 'Indica exclusão lógica do alerta: S = ativo, N = inativo.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_CRIADO_EM IS 'Data e hora de criação do registro.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_ATUALIZADO_EM IS 'Data e hora da última atualização do registro.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DT_DELETADO_EM IS 'Data e hora da exclusão lógica.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.ID_DELETADO_POR IS 'Identificador do usuário que realizou a exclusão lógica, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_ALERTA.DS_MOTIVO_EXCLUSAO IS 'Justificativa opcional para auditoria da exclusão lógica.';

CREATE TABLE TB_AMANAJE_INDICADOR_REGIONAL (
    ID_INDICADOR NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER,
    SG_ESTADO CHAR(2) NOT NULL,
    NM_CIDADE VARCHAR2(100) NOT NULL,
    NM_REGIAO VARCHAR2(150),
    TP_RISCO VARCHAR2(30) NOT NULL,
    NR_SCORE_MEDIO NUMBER(5,2) NOT NULL,
    TP_NIVEL_RISCO_MEDIO VARCHAR2(20) NOT NULL,
    QT_ESTACOES NUMBER(6) DEFAULT 0 NOT NULL,
    QT_ALERTAS_ATIVOS NUMBER(6) DEFAULT 0 NOT NULL,
    NM_FONTE_CALCULO VARCHAR2(100) NOT NULL,
    DT_CALCULO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_INDICADOR PRIMARY KEY (ID_INDICADOR),
    CONSTRAINT CK_AMANAJE_INDICADOR_ESTADO CHECK (REGEXP_LIKE(SG_ESTADO, '^[A-Z]{2}$')),
    CONSTRAINT CK_AMANAJE_INDICADOR_TIPO CHECK (TP_RISCO IN ('ENCHENTE', 'DESLIZAMENTO', 'TEMPESTADE', 'QUALIDADE_AR')),
    CONSTRAINT CK_AMANAJE_INDICADOR_SCORE CHECK (NR_SCORE_MEDIO BETWEEN 0 AND 100),
    CONSTRAINT CK_AMANAJE_INDICADOR_NIVEL CHECK (TP_NIVEL_RISCO_MEDIO IN ('BAIXO', 'MODERADO', 'ALTO', 'CRITICO')),
    CONSTRAINT CK_AMANAJE_INDICADOR_EST CHECK (QT_ESTACOES >= 0),
    CONSTRAINT CK_AMANAJE_INDICADOR_ALT CHECK (QT_ALERTAS_ATIVOS >= 0),
    CONSTRAINT CK_AMANAJE_INDICADOR_SCORE_NIVEL CHECK (
        (TP_NIVEL_RISCO_MEDIO = 'BAIXO' AND NR_SCORE_MEDIO >= 0 AND NR_SCORE_MEDIO < 25)
        OR
        (TP_NIVEL_RISCO_MEDIO = 'MODERADO' AND NR_SCORE_MEDIO >= 25 AND NR_SCORE_MEDIO < 50)
        OR
        (TP_NIVEL_RISCO_MEDIO = 'ALTO' AND NR_SCORE_MEDIO >= 50 AND NR_SCORE_MEDIO < 75)
        OR
        (TP_NIVEL_RISCO_MEDIO = 'CRITICO' AND NR_SCORE_MEDIO >= 75 AND NR_SCORE_MEDIO <= 100)
    ),
    CONSTRAINT FK_INDICADOR_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONITORADA (ID_REGIAO)
);

COMMENT ON TABLE TB_AMANAJE_INDICADOR_REGIONAL IS 'Indicadores agregados por cidade, estado ou zona de risco, sem exposição de dados privados identificáveis.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.ID_INDICADOR IS 'Identificador único do indicador regional.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.ID_REGIAO IS 'Região monitorada relacionada ao indicador, quando houver vínculo direto.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.SG_ESTADO IS 'Sigla da unidade federativa do indicador.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.NM_CIDADE IS 'Cidade agregada no indicador.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.NM_REGIAO IS 'Nome agregado da região, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.TP_RISCO IS 'Tipo de risco consolidado no indicador.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.NR_SCORE_MEDIO IS 'Score médio calculado para o indicador.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.TP_NIVEL_RISCO_MEDIO IS 'Nível médio de risco associado ao score médio.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.QT_ESTACOES IS 'Quantidade de estações consideradas no cálculo.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.QT_ALERTAS_ATIVOS IS 'Quantidade de alertas ativos considerados no cálculo.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.NM_FONTE_CALCULO IS 'Origem ou rotina responsável pelo cálculo do indicador.';
COMMENT ON COLUMN TB_AMANAJE_INDICADOR_REGIONAL.DT_CALCULO IS 'Data e hora do cálculo do indicador.';

CREATE TABLE TB_AMANAJE_HISTORICO_EVENTO (
    ID_EVENTO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_USUARIO NUMBER,
    NM_ENTIDADE VARCHAR2(80) NOT NULL,
    ID_ENTIDADE NUMBER NOT NULL,
    TP_ACAO VARCHAR2(30) NOT NULL,
    DS_EVENTO VARCHAR2(1000) NOT NULL,
    DT_EVENTO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_HIST_EVENTO PRIMARY KEY (ID_EVENTO),
    CONSTRAINT CK_AMANAJE_HIST_ACAO CHECK (TP_ACAO IN ('CRIACAO', 'ATUALIZACAO', 'EXCLUSAO_LOGICA', 'INVALIDACAO', 'AVALIACAO_RISCO', 'GERACAO_ALERTA', 'RESOLUCAO_ALERTA', 'LOGIN', 'INTEGRACAO_EXTERNA', 'OUTRA')),
    CONSTRAINT FK_HIST_USUARIO FOREIGN KEY (ID_USUARIO)
        REFERENCES TB_AMANAJE_USUARIO (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_HISTORICO_EVENTO IS 'Registro genérico de ações relevantes para rastreabilidade e auditoria.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.ID_EVENTO IS 'Identificador único do evento histórico.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.ID_USUARIO IS 'Usuário associado ao evento, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.NM_ENTIDADE IS 'Nome lógico da entidade afetada pelo evento.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.ID_ENTIDADE IS 'Identificador do registro afetado na entidade de origem.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.TP_ACAO IS 'Tipo de ação registrada.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.DS_EVENTO IS 'Descrição do evento para auditoria.';
COMMENT ON COLUMN TB_AMANAJE_HISTORICO_EVENTO.DT_EVENTO IS 'Data e hora de ocorrência do evento.';

CREATE TABLE TB_AMANAJE_LOG_STATUS_ESTACAO (
    ID_LOG NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_ESTACAO NUMBER NOT NULL,
    NR_UPTIME_SEG NUMBER(12),
    NR_RSSI NUMBER(6,2),
    DS_IP_ADDRESS VARCHAR2(45),
    DS_VERSAO_FIRMWARE VARCHAR2(40),
    DT_REGISTRO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_LOG_ESTACAO PRIMARY KEY (ID_LOG),
    CONSTRAINT CK_AMANAJE_LOG_UPTIME CHECK (NR_UPTIME_SEG IS NULL OR NR_UPTIME_SEG >= 0),
    CONSTRAINT FK_LOG_ESTACAO FOREIGN KEY (ID_ESTACAO)
        REFERENCES TB_AMANAJE_ESTACAO_IOT (ID_ESTACAO)
);

COMMENT ON TABLE TB_AMANAJE_LOG_STATUS_ESTACAO IS 'Histórico de mensagens de diagnóstico técnico e integridade das estações IoT.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.ID_LOG IS 'Identificador único do log de status.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.ID_ESTACAO IS 'Estação IoT relacionada ao log.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.NR_UPTIME_SEG IS 'Tempo de atividade da estação em segundos.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.NR_RSSI IS 'Intensidade do sinal Wi-Fi ou rádio informada pela estação.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.DS_IP_ADDRESS IS 'Endereço IP informado pela estação.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.DS_VERSAO_FIRMWARE IS 'Versão de firmware da estação.';
COMMENT ON COLUMN TB_AMANAJE_LOG_STATUS_ESTACAO.DT_REGISTRO IS 'Data e hora de registro do status.';

CREATE TABLE TB_AMANAJE_PROCESSAMENTO (
    ID_PROCESSAMENTO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_REGIAO NUMBER,
    ID_USUARIO NUMBER,
    TP_PROCESSAMENTO VARCHAR2(40) NOT NULL,
    ST_PROCESSAMENTO VARCHAR2(20) DEFAULT 'INICIADO' NOT NULL,
    DS_ORIGEM VARCHAR2(120) NOT NULL,
    DS_PARAMETROS VARCHAR2(1000),
    DS_RESULTADO VARCHAR2(1000),
    DT_INICIO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,
    DT_FIM TIMESTAMP,

    CONSTRAINT PK_AMANAJE_PROCESSAMENTO PRIMARY KEY (ID_PROCESSAMENTO),
    CONSTRAINT CK_AMANAJE_PROCESSAMENTO_TIPO CHECK (TP_PROCESSAMENTO IN ('SINCRONIZACAO_CLIMATICA', 'CALCULO_RISCO', 'GERACAO_INDICADOR', 'GERACAO_ALERTA', 'CARGA_DADOS', 'ROTINA_PL_SQL', 'OUTRO')),
    CONSTRAINT CK_AMANAJE_PROCESSAMENTO_STATUS CHECK (ST_PROCESSAMENTO IN ('INICIADO', 'EM_EXECUCAO', 'CONCLUIDO', 'FALHOU', 'CANCELADO')),
    CONSTRAINT CK_AMANAJE_PROCESSAMENTO_FIM CHECK (DT_FIM IS NULL OR DT_FIM >= DT_INICIO),
    CONSTRAINT FK_PROCESSAMENTO_REGIAO FOREIGN KEY (ID_REGIAO)
        REFERENCES TB_AMANAJE_REGIAO_MONITORADA (ID_REGIAO),
    CONSTRAINT FK_PROCESSAMENTO_USUARIO FOREIGN KEY (ID_USUARIO)
        REFERENCES TB_AMANAJE_USUARIO (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_PROCESSAMENTO IS 'Registro de execuções e processamentos, como sincronização climática, cálculo de risco, geração de indicadores e rotinas PL/SQL.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.ID_PROCESSAMENTO IS 'Identificador único do processamento.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.ID_REGIAO IS 'Região monitorada relacionada ao processamento, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.ID_USUARIO IS 'Usuário responsável ou associado ao processamento, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.TP_PROCESSAMENTO IS 'Tipo de processamento executado pelo sistema.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.ST_PROCESSAMENTO IS 'Status atual da execução do processamento.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.DS_ORIGEM IS 'Origem do processamento, como API Java, serviço C#, carga DML ou bloco PL/SQL.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.DS_PARAMETROS IS 'Parâmetros de entrada usados na execução.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.DS_RESULTADO IS 'Resultado resumido da execução.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.DT_INICIO IS 'Data e hora de início do processamento.';
COMMENT ON COLUMN TB_AMANAJE_PROCESSAMENTO.DT_FIM IS 'Data e hora de término do processamento.';

CREATE TABLE TB_AMANAJE_LOG_ERRO (
    ID_LOG_ERRO NUMBER GENERATED BY DEFAULT AS IDENTITY,
    ID_PROCESSAMENTO NUMBER,
    ID_USUARIO NUMBER,
    NM_ORIGEM VARCHAR2(120) NOT NULL,
    NM_OBJETO VARCHAR2(120),
    CD_ERRO NUMBER,
    DS_ERRO VARCHAR2(1000) NOT NULL,
    DS_COMANDO VARCHAR2(4000),
    DT_ERRO TIMESTAMP DEFAULT SYSTIMESTAMP NOT NULL,

    CONSTRAINT PK_AMANAJE_LOG_ERRO PRIMARY KEY (ID_LOG_ERRO),
    CONSTRAINT FK_LOG_ERRO_PROCESSAMENTO FOREIGN KEY (ID_PROCESSAMENTO)
        REFERENCES TB_AMANAJE_PROCESSAMENTO (ID_PROCESSAMENTO),
    CONSTRAINT FK_LOG_ERRO_USUARIO FOREIGN KEY (ID_USUARIO)
        REFERENCES TB_AMANAJE_USUARIO (ID_USUARIO)
);

COMMENT ON TABLE TB_AMANAJE_LOG_ERRO IS 'Registro técnico de erros ocorridos em cargas, blocos PL/SQL, integrações e processamentos do banco.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.ID_LOG_ERRO IS 'Identificador único do log de erro.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.ID_PROCESSAMENTO IS 'Processamento relacionado ao erro, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.ID_USUARIO IS 'Usuário associado ao erro, quando aplicável.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.NM_ORIGEM IS 'Origem do erro, como DML, PL/SQL, API, integração externa ou rotina de carga.';
COMMENT ON COLUMN TB_AMANAJE_LOG_ERRO.NM_OBJETO IS 'Nome do objeto ou bloco relacionado ao erro.';
